import WidgetKit
import SwiftUI
import AppIntents
import RealityKit

struct ObjectIntent: AppIntent {
    static var title: LocalizedStringResource = "3D Object"
    @Parameter(title: "Object Name") var objectName: String
}

struct ObjectWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: "ObjectWidget",
            intent: ObjectIntent.self,
            provider: .static
        ) { entry in
            RealityView { content in
                if let model = try? await ModelEntity(named: entry.objectName) {
                    content.add(model)
                }
            }
        }
    }
}

